package com.hospital.management.controller.admission;import com.hospital.management.service.*;import com.hospital.management.service.impl.BedServiceImpl;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/admin/beds/status")public class BedStatusServlet extends HttpServlet{private final BedService s;public BedStatusServlet(){this(new BedServiceImpl());}BedStatusServlet(BedService s){this.s=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws IOException{r.sendError(405);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws IOException{Long id=AdmissionRequest.id(q.getParameter("bedId"));if(id==null){r.sendError(400);return;}s.updateBedStatus(id,q.getParameter("action"),AdmissionRequest.audit(q));r.sendRedirect(q.getContextPath()+"/admin/beds/view?id="+id);}}
